import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Communication Templates","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Communication Templates | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/communication-templates"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Communication Templates | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/communication-templates"}]]},"headers":[],"relativePath":"user-guide/communication-templates.md","filePath":"user-guide/communication-templates.md","lastUpdated":1784758619000}'),s={name:"user-guide/communication-templates.md"};function i(r,e,l,p,m,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="communication-templates" tabindex="-1">Communication Templates <a class="header-anchor" href="#communication-templates" aria-label="Permalink to &quot;Communication Templates&quot;">​</a></h1><p>Create reusable <strong>plain-text</strong> messages for WhatsApp (and future channels). Templates support clickable placeholders such as lead name, agent name, and workspace name.</p><p>SaleOS does not send messages for you. WhatsApp opens in a new tab with the message pre-filled.</p><h2 id="manage-templates" tabindex="-1">Manage templates <a class="header-anchor" href="#manage-templates" aria-label="Permalink to &quot;Manage templates&quot;">​</a></h2><ol><li>Open <strong>Templates</strong> in the workspace navigation (requires the Communication Templates module and view permission).</li><li>Click <strong>New template</strong>.</li><li>Enter a name, choose context (e.g. Leads), channel (WhatsApp), optional category, and message body.</li><li>Click placeholder chips to insert tokens at the cursor (or replace selected text).</li><li>Save. Toggle <strong>Active</strong> off to hide a template from pickers without deleting it.</li></ol><h2 id="send-via-whatsapp-from-a-lead" tabindex="-1">Send via WhatsApp from a Lead <a class="header-anchor" href="#send-via-whatsapp-from-a-lead" aria-label="Permalink to &quot;Send via WhatsApp from a Lead&quot;">​</a></h2><ol><li>Open a lead that has a phone number.</li><li>Click <strong>WhatsApp</strong> next to the phone field.</li><li>Pick a template and review the preview, <strong>or</strong> open a blank chat if you have no templates (or do not want one).</li><li>WhatsApp Web (or the WhatsApp app) opens. Send from WhatsApp as usual.</li></ol><p>There is no outbound message history in this version.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Typical roles</th></tr></thead><tbody><tr><td>View / use templates</td><td>Admin, Manager, Staff</td></tr><tr><td>Create / update</td><td>Admin, Manager</td></tr><tr><td>Delete</td><td>Admin</td></tr></tbody></table><p>Workspace owners (superadmin) have full access.</p>',11)])])}const u=t(s,[["render",i]]);export{h as __pageData,u as default};
